package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

class CSVFormatTest {

    @Test
    void testWithIgnoreHeaderCase() {
        CSVFormat csvFormat = CSVFormat.DEFAULT;
        CSVFormat result = csvFormat.withIgnoreHeaderCase(true);
        assertNotNull(result);
        // It should return a new CSVFormat instance with ignoreHeaderCase = true
        assertTrue(result.getIgnoreHeaderCase());
        // Original instance should remain unchanged
        assertFalse(csvFormat.getIgnoreHeaderCase());
    }
}
